sp_widget.client_script:
function($scope) {
    var c = this;

    // --- Init from server data (no c.server.get on init) ---
    c.slots       = c.data.slots       || [];
    c.alreadyBooked = c.data.alreadyBooked || false;
    c.weekOffset  = 0;
    c.selectedSlot = null;
    c.booking     = false;
    c.message     = '';
    c.messageType = '';

    var DAYS    = ['Monday', 'Wednesday', 'Friday'];
    var OFFSETS = [0, 2, 4]; // days from Monday

    c.computeWeekDates = function() {
        var now = new Date();
        now.setDate(now.getDate() + c.weekOffset * 7);
        var dow = now.getDay(); // 0=Sun
        var monday = new Date(now);
        monday.setDate(now.getDate() - ((dow + 6) % 7));

        c.weekDates = OFFSETS.map(function(offset, i) {
            var d = new Date(monday);
            d.setDate(monday.getDate() + offset);
            return {
                label:   DAYS[i],
                date:    d.toISOString().split('T')[0],
                display: d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short' })
            };
        });
        c.weekLabel = c.weekDates[0].display + ' – ' + c.weekDates[2].display;
    };

    // Initial week dates (no server call needed)
    c.computeWeekDates();

    // Called only on user-triggered week nav (c.server available here)
    c.loadSlots = function() {
        c.slots = [];
        c.selectedSlot = null;
        c.computeWeekDates();
        c.server.get({
            action: 'getSlots',
            dates: c.weekDates.map(function(d) { return d.date; })
        }).then(function(r) {
            c.slots        = r.data.slots;
            c.alreadyBooked = r.data.alreadyBooked;
        });
    };

    c.prevWeek = function() { c.weekOffset--; c.loadSlots(); };
    c.nextWeek = function() { c.weekOffset++; c.loadSlots(); };

    c.selectSlot = function(slot) {
        if (slot.available && !c.alreadyBooked) c.selectedSlot = slot;
    };

    c.confirmBooking = function() {
        if (!c.selectedSlot) return;
        c.booking = true;
        c.server.get({
            action:    'bookLesson',
            startTime: c.selectedSlot.startValue,
            endTime:   c.selectedSlot.endValue
        }).then(function(r) {
            c.booking = false;
            if (r.data.success) {
                c.messageType   = 'success';
                c.message       = 'Lesson booked! Confirmation email sent.';
                c.selectedSlot  = null;
                c.alreadyBooked = true;
                c.loadSlots();
            } else {
                c.messageType = 'danger';
                c.message     = r.data.error;
            }
        });
    };

    c.getSlotsForDate = function(date) {
        return (c.slots || []).filter(function(s) { return s.date === date; });
    };
}

sp_widget.css:
.german-calendar {
    font-family: inherit;
}
.week-nav {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 16px;
}
.week-nav h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 600;
}
.calendar-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
}
.day-col {
    background: #f8f9fa;
    border-radius: 6px;
    overflow: hidden;
}
.day-header {
    background: #0060a9;
    color: #fff;
    padding: 10px;
    text-align: center;
    font-weight: 600;
    font-size: 13px;
}
.day-header small {
    display: block;
    font-weight: 400;
    font-size: 11px;
    opacity: 0.85;
}
.slot-list {
    padding: 8px;
}
.slot-btn {
    display: block;
    width: 100%;
    margin-bottom: 6px;
    padding: 8px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 13px;
    text-align: center;
    transition: all 0.15s;
}
.slot-btn.available:hover {
    border-color: #0060a9;
    color: #0060a9;
}
.slot-btn.selected {
    background: #0060a9;
    color: #fff;
    border-color: #0060a9;
}
.slot-btn.full {
    background: #f8d7da;
    color: #721c24;
    border-color: #f5c6cb;
    cursor: not-allowed;
    opacity: 0.7;
}
.slot-btn.locked {
    opacity: 0.5;
    cursor: not-allowed;
}
.booking-confirm {
    margin-top: 20px;
    padding: 16px;
    background: #e8f4fd;
    border-radius: 6px;
    border-left: 4px solid #0060a9;
}
.already-booked-notice {
    padding: 12px 16px;
    background: #fff3cd;
    border-radius: 6px;
    margin-bottom: 16px;
    font-size: 13px;
}
.no-slots {
    color: #6c757d;
    font-size: 12px;
    text-align: center;
    padding: 8px;
}

sp_widget.script:
(function() {

    function pad(n) { return n < 10 ? '0' + n : '' + n; }

    function buildSlots(dates) {
        var availability = new x_608645_my_comp_0.LessonAvailability();
        var slots = [];
        var startHours = [9, 10, 11, 13];
        for (var d = 0; d < dates.length; d++) {
            for (var h = 0; h < startHours.length; h++) {
                var s = new GlideDateTime();
                s.setDisplayValueInternal(dates[d] + ' ' + pad(startHours[h]) + ':00:00');
                var e = new GlideDateTime(s);
                e.addSeconds(3600);
                slots.push({
                    date:       dates[d],
                    label:      pad(startHours[h]) + ':00 – ' + pad(startHours[h] + 1) + ':00',
                    startValue: s.getValue(),
                    endValue:   e.getValue(),
                    available:  availability.isSlotAvailable(s.getValue(), e.getValue())
                });
            }
        }
        return slots;
    }

    function currentWeekDates() {
        // Server-side: compute Mon/Wed/Fri for the current week
        var now = new GlideDateTime();
        var dow = now.getDayOfWeekLocalTime(); // 1=Sun,2=Mon,...,7=Sat
        var daysToMonday = (dow === 1) ? 6 : (dow - 2);
        var monday = new GlideDateTime(now);
        monday.addDaysLocalTime(-daysToMonday);
        var dates = [];
        var offsets = [0, 2, 4];
        for (var i = 0; i < offsets.length; i++) {
            var d = new GlideDateTime(monday);
            d.addDaysLocalTime(offsets[i]);
            dates.push(d.getLocalDate().getByFormat('yyyy-MM-dd'));
        }
        return dates;
    }

    var action = (input && input.action) ? input.action : '';

    if (!action || action === 'getSlots') {
        var dates = (action === 'getSlots') ? input.dates : currentWeekDates();
        var availability = new x_608645_my_comp_0.LessonAvailability();
        data.slots        = buildSlots(dates);
        data.alreadyBooked = availability.hasStudentBookedThisWeek(gs.getUserID());

    } else if (action === 'bookLesson') {
        try {
            var availability = new x_608645_my_comp_0.LessonAvailability();

            if (availability.hasStudentBookedThisWeek(gs.getUserID())) {
                data.success = false;
                data.error = 'You already have a lesson booked this week.';
                return;
            }
            if (!availability.isSlotAvailable(input.startTime, input.endTime)) {
                data.success = false;
                data.error = 'Slot no longer available. Choose another.';
                return;
            }

            // Find an available teacher for this slot
            var teacherSysId = '';
            var roleGr = new GlideRecord('sys_user_has_role');
            roleGr.addQuery('role', '1835f20d83100310345ba730ceaad351');
            roleGr.addQuery('user.active', true);
            roleGr.query();
            while (roleGr.next()) {
                var tId = roleGr.getValue('user');
                var check = new GlideRecord('x_608645_my_comp_0_lesson');
                check.addQuery('teacher', tId);
                check.addQuery('start_time', input.startTime);
                check.addQuery('status', 'NOT IN', 'no_show');
                check.query();
                if (!check.hasNext()) { teacherSysId = tId; break; }
            }

            if (!teacherSysId) {
                data.success = false;
                data.error = 'No available teacher for this slot.';
                return;
            }

            var lesson = new GlideRecord('x_608645_my_comp_0_lesson');
            lesson.initialize();
            lesson.setValue('student',    gs.getUserID());
            lesson.setValue('teacher',    teacherSysId);
            lesson.setValue('start_time', input.startTime);
            lesson.setValue('end_time',   input.endTime);
            lesson.setValue('status',     'scheduled');
            lesson.insert();
            data.success = true;

        } catch (e) {
            data.success = false;
            data.error = e.toString();
        }
    }

})();
